func:
// MOTOR DE SIMULACAO DO ARDUINO
// Emite o MESMO objeto do Arduino (apos parse JSON):
//   {temp, proc, rodando, bomba, aquec, dec} + extras p/ UI
// Entradas (1 input, desambiguadas por topic/payload):
//   msg.topic==='tick'  -> avanca a simulacao
//   msg.payload==='P'   -> inicia/pausa processo
//   msg.payload==='B'   -> liga/desliga bomba (so parado)
//   payload === chave de receita -> troca receita
//
// AUTO-SWITCH: se o Arduino real enviou dado nos ultimos 5s, o simulador RECUA.
if (Date.now() - (flow.get('lastReal') || 0) < 5000) return null;

const RECEITAS = {
  teste:  { nome:'Teste / Padrao', etapas:[ {nome:'Mostura 65C', temp:65, durMin:2} ] },
  pilsen: { nome:'Pilsen (mostura por etapas)', etapas:[
      {nome:'Patamar proteico', temp:52, durMin:15},
      {nome:'Sacarificacao',    temp:63, durMin:40},
      {nome:'Mash-out',         temp:78, durMin:5} ] },
  apa:    { nome:'American Pale Ale', etapas:[
      {nome:'Sacarificacao', temp:67, durMin:45},
      {nome:'Mash-out',      temp:78, durMin:8} ] }
};
const AMBIENTE = 25.0;
const HIST = 0.5;

let s = context.get('s');
if (!s) {
  s = { receita:'teste', etapa:0, temp:AMBIENTE, rodando:false, bomba:false,
        aquec:false, decSeg:0, concluido:false, atingiu:false };
  context.set('s', s);
}

function getRec(st) {
  if (st.receita === 'custom') {
    const c = context.get('customReceita');
    if (c && c.etapas && c.etapas.length) return c;
  }
  return RECEITAS[st.receita] || RECEITAS.teste;
}

function emitir() {
  const st = context.get('s');
  const rec = getRec(st);
  const et = rec.etapas[Math.min(st.etapa, rec.etapas.length-1)];
  return { payload: {
    // compativel com o Arduino real:
    temp: Math.round(st.temp*10)/10,
    proc: st.etapa+1,
    rodando: st.rodando ? 1 : 0,
    bomba: st.bomba ? 1 : 0,
    aquec: st.aquec ? 1 : 0,
    dec: Math.round(st.decSeg*1000),
    // extras p/ a UI:
    receita: rec.nome,
    receitaKey: st.receita,
    etapaNome: et.nome,
    etapaIdx: st.etapa+1,
    etapaTotal: rec.etapas.length,
    setpoint: et.temp,
    etapaDurSeg: et.durMin*60,
    concluido: st.concluido,
    aguardandoTemp: st.rodando && !st.atingiu && !st.concluido
  }};
}

const topic = msg.topic;
const p = msg.payload;

// troca de receita
if (topic === 'receita' || (typeof p === 'string' && RECEITAS[p])) {
  if (RECEITAS[p]) s.receita = p;
  s.etapa = 0; s.rodando = false; s.bomba = false; s.aquec = false;
  s.decSeg = 0; s.concluido = false; s.temp = AMBIENTE; s.atingiu = false;
  context.set('s', s);
  return emitir();
}

// receita personalizada (vinda do construtor drag & drop)
if (topic === 'receita_custom') {
  const arr = (msg.payload && Array.isArray(msg.payload.etapas)) ? msg.payload.etapas : [];
  if (arr.length) {
    const nomeRec = (msg.payload && msg.payload.nome) ? msg.payload.nome : 'Personalizada';
    context.set('customReceita', { nome: nomeRec, etapas: arr });
    s.receita = 'custom'; s.etapa = 0; s.rodando = false; s.bomba = false;
    s.aquec = false; s.decSeg = 0; s.concluido = false; s.atingiu = false; s.temp = AMBIENTE;
    context.set('s', s);
  }
  return emitir();
}

// comando P (processo)
if (p === 'P') {
  if (!s.rodando) {
    if (s.concluido) { s.etapa = 0; s.decSeg = 0; s.concluido = false; s.temp = AMBIENTE; s.atingiu = false; }
    s.rodando = true; s.bomba = false;
  } else {
    s.rodando = false;
  }
  context.set('s', s);
  return emitir();
}

// comando B (bomba) — pode ligar/desligar tambem DURANTE o processo
if (p === 'B') {
  s.bomba = !s.bomba; context.set('s', s);
  return emitir();
}

// tick: avanco da simulacao
if (topic === 'tick') {
  const rec = getRec(s);
  const totalSeg = rec.etapas.reduce(function(a,e){ return a + e.durMin*60; }, 0);
  const menorSeg = rec.etapas.reduce(function(a,e){ return Math.min(a, e.durMin*60); }, Infinity);
  // tempo acelerado p/ visualizacao: receita inteira em ~40s,
  // mas garantindo que ate a etapa mais curta tenha >= 6 passos (patamar visivel)
  const passoSeg = Math.max(1, Math.min(totalSeg/40, menorSeg/6));

  if (s.rodando) {
    const et = rec.etapas[Math.min(s.etapa, rec.etapas.length-1)];
    const sp = et.temp;
    // sobe e ASSENTA no setpoint (patamar limpo), independente da aceleracao
    s.temp += (sp - s.temp) * 0.5;
    s.aquec = (s.temp < sp - HIST);                    // LED: aquecendo enquanto abaixo do alvo
    // o TEMPO so comeca a contar APOS atingir a temperatura do patamar
    if (!s.atingiu && s.temp >= sp - HIST) s.atingiu = true;
    if (s.atingiu) {
      const durSeg = et.durMin*60;
      s.decSeg += passoSeg;
      if (s.decSeg >= durSeg) {
        if (s.etapa < rec.etapas.length-1) { s.etapa++; s.decSeg = 0; s.atingiu = false; }  // proxima etapa espera o alvo
        else { s.decSeg = durSeg; s.rodando = false; s.concluido = true; }                  // clamp + conclui
      }
    }
    // bomba: SEM intertravamento (pode ligar durante o processo)
  } else {
    s.aquec = false;
    if (!s.concluido) s.temp += (AMBIENTE - s.temp) * 0.03;   // esfria so se PAUSADO (concluido segura)
  }
  context.set('s', s);
  return emitir();
}

return null;

// Varre as portas seriais, acha o Arduino e configura o no serial sozinho.
// (zero ajuste manual de porta COM)
const conhecidos = ['2341','2a03','1a86','0403','10c4','1b4f','03eb','1eaf']; // vendorIds comuns
function pontua(p){
  const vid  = (p.vendorId || '').toLowerCase();
  const man  = (p.manufacturer || '').toLowerCase();
  const path = (p.path || '');
  if (/standard port types/.test(man)) return -1;     // porta da placa-mae
  if (/^ACPI/i.test(p.pnpId || '')) return -1;
  let s = 0;
  if (conhecidos.indexOf(vid) >= 0) s += 10;
  if (/arduino|wch|ch34|ft232|ftdi|silicon ?labs|cp210|usb.?serial|usb2\.0-serial/.test(man)) s += 8;
  if (/usbserial|usbmodem|ttyusb|ttyacm/i.test(path)) s += 3;
  if (/^com\d+$/i.test(path)) s += 1;
  return s;
}
return serialport.SerialPort.list().then(function(ports){
  let best = null, bestScore = 0;
  ports.forEach(function(p){ const sc = pontua(p); if (sc > bestScore){ bestScore = sc; best = p.path; } });
  const estado = flow.get('serialState') || '';
  if (best){
    const novo = 'on:' + best;
    if (estado !== novo){                                   // so age na transicao
      flow.set('serialState', novo);
      node.status({ fill:'green', shape:'dot', text:'Arduino em ' + best });
      return { payload: { serialport: best, serialbaud:'9600', databits:'8', parity:'none',
                          stopbits:'1', dtr:'none', rts:'none', cts:'none', dsr:'none', enabled:true } };
    }
    return null;                                            // ja conectado nessa porta
  }
  if (estado !== 'off'){                                    // nenhum Arduino: fecha o serial (sem ruido)
    flow.set('serialState','off');
    node.status({ fill:'grey', shape:'ring', text:'Sem Arduino - simulacao' });
    return { payload: { enabled:false } };
  }
  return null;
}).catch(function(e){ node.warn('auto-detect serial: ' + e.message); return null; });

// Recebe o objeto de estado (do simulador OU do Arduino real apos parse).
// Tolera ausencia dos campos extras (Arduino real so manda 6 campos).
const d = msg.payload;
if (typeof d !== 'object' || d === null || d.temp === undefined) return null;

const setpoint = (d.setpoint !== undefined) ? d.setpoint : 65;  // fallback Arduino real

flow.set('rodando', d.rodando);
flow.set('bomba', d.bomba);
flow.set('ultima_temp', d.temp);   // <- corrige o bug do alerta antigo

const estado = {
  temp: d.temp,
  setpoint: setpoint,
  rodando: !!d.rodando,
  bomba: !!d.bomba,
  aquec: !!d.aquec,
  // fallbacks p/ quando vier o Arduino real (so 6 campos, sem os extras de receita):
  receita: d.receita || 'Arduino (firmware atual)',
  etapaNome: d.etapaNome || ('Etapa ' + (d.proc || 1)),
  etapaIdx: d.etapaIdx || (d.proc || 1),
  etapaTotal: d.etapaTotal || 1,
  decSeg: Math.floor((d.dec || 0) / 1000),
  etapaDurSeg: d.etapaDurSeg || (d.proc === 1 ? 120 : 0),
  concluido: !!d.concluido,
  alerta: d.temp > 80,
  // "aquecendo ate o alvo": usa o flag do simulador; p/ Arduino real, infere por temp < alvo
  aguardandoTemp: (d.aguardandoTemp !== undefined) ? !!d.aguardandoTemp
                  : (!!d.rodando && !d.concluido && (d.temp < setpoint - 0.5))
};

return [
  { payload: d.temp },                                                   // 1 -> gauge
  [ {topic:'Real', payload: d.temp}, {topic:'Alvo', payload: setpoint} ],// 2 -> chart (2 msgs)
  { payload: estado }                                                    // 3 -> card status
];

const RECEITAS = {
  teste:  [ {temp:65, durMin:2} ],
  pilsen: [ {temp:52, durMin:15}, {temp:63, durMin:40}, {temp:78, durMin:5} ],
  apa:    [ {temp:67, durMin:45}, {temp:78, durMin:8} ]
};
let etapas = null;
if (msg.topic === 'receita_custom' && msg.payload && Array.isArray(msg.payload.etapas)) {
  etapas = msg.payload.etapas;
} else if (typeof msg.payload === 'string' && RECEITAS[msg.payload]) {
  etapas = RECEITAS[msg.payload];
}
if (!etapas || !etapas.length) return null;
const r = 'R' + etapas.map(function(e){ return Math.round(e.temp) + ',' + Math.round(e.durMin); }).join(';') + '\n';
return { payload: r };
